function generateProceduralTrack(circuitId: string): CircuitDetails {
  let hash = 0;
  for (let i = 0; i < circuitId.length; i++) {
    hash = circuitId.charCodeAt(i) + ((hash << 5) - hash);
  }
  const seed = Math.abs(hash);

  const pseudoRandom = (offset: number) => {
    const x = Math.sin(seed + offset) * 10000;
    return x - Math.floor(x);
  };

  const numPoints = 8;
  const points: Array<{ x: number; y: number }> = [];
  const cx = 300;
  const cy = 200;

  for (let i = 0; i < numPoints; i++) {
    const angle = (i * 2 * Math.PI) / numPoints;
    const r = 110 + pseudoRandom(i * 17) * 75 - 35;
    const x = Math.round(cx + r * Math.cos(angle));
    const y = Math.round(cy + r * Math.sin(angle) * 0.8);
    points.push({ x, y });
  }

  const getSplinePath = (pts: typeof points, start: number, end: number, isClosed: boolean): string => {
    const n = pts.length;
    let d = `M ${pts[start].x},${pts[start].y}`;
    const steps = end - start;

    for (let i = 0; i < steps; i++) {
      const idx = start + i;
      const p0 = pts[(idx - 1 + n) % n];
      const p1 = pts[idx % n];
      const p2 = pts[(idx + 1) % n];
      const p3 = pts[(idx + 2) % n];

      const cp1x = p1.x + (p2.x - p0.x) / 6;
      const cp1y = p1.y + (p2.y - p0.y) / 6;
      const cp2x = p2.x - (p3.x - p1.x) / 6;
      const cp2y = p2.y - (p3.y - p1.y) / 6;

      d += ` C ${cp1x},${cp1y} ${cp2x},${cp2y} ${p2.x},${p2.y}`;
    }
    if (isClosed) d += ' Z';
    return d;
  };

  const s1 = getSplinePath(points, 0, 3, false);
  const s2 = getSplinePath(points, 3, 6, false);
  const s3 = getSplinePath(points, 6, 8, false);
  const fullPath = getSplinePath(points, 0, 8, true);

  const corners = points.map((p, idx) => ({
    n: String(idx + 1).padStart(2, '0'),
    x: p.x + (p.x > cx ? 12 : -12),
    y: p.y + (p.y > cy ? 12 : -12)
  }));

  const speedTrap = {
    x: Math.round((points[1].x + points[2].x) / 2),
    y: Math.round((points[1].y + points[2].y) / 2)
  };

  const startFinish = {
    x: points[0].x,
    y: points[0].y,
    angle: 0
  };

  const capitalizedName = circuitId.charAt(0).toUpperCase() + circuitId.slice(1).replace(/_/g, ' ');

  return {
    name: `${capitalizedName} Circuit`,
    country: 'International',
    flag: '🏁',
    length: `${(4.8 + pseudoRandom(99) * 2.2).toFixed(3)} KM`,
    distance: `${(305.0 + pseudoRandom(123) * 6).toFixed(2)} KM`,
    laps: Math.round(48 + pseudoRandom(456) * 24),
    record: `1:${(15 + pseudoRandom(789) * 16).toFixed(0)}.${Math.floor(pseudoRandom(999) * 1000)} (2024)`,
    champion: 'Max Verstappen',
    s1,
    s2,
    s3,
    fullPath,
    corners,
    speedTrap,
    startFinish
  };
}

interface CircuitMapProps {
  circuitId: string;
  drivers?: DriverProgress[];
  showStats?: boolean;
  activeDriverCode?: string;
  onHoverDriver?: (code: string | null) => void;
}

export default function CircuitMap({
  circuitId,
  drivers = [],
  showStats = true,
  activeDriverCode = '',
  onHoverDriver
}: CircuitMapProps) {
  const normId = ID_MAP[circuitId?.toLowerCase()] || (CIRCUIT_DATA[circuitId?.toLowerCase()] ? circuitId?.toLowerCase() : null);
  const track = normId 
    ? (CIRCUIT_DATA[normId] || CIRCUIT_DATA.default) 
    : generateProceduralTrack(circuitId || 'default');

  const pathRef = useRef<SVGPathElement | null>(null);
  const [pathLength, setPathLength] = useState(0);
  const [driverPoints, setDriverPoints] = useState<Record<string, { x: number; y: number; code: string; color: string; position: number; status: string }>>({});
  const [virtualLapProgress, setVirtualLapProgress] = useState(0);

  useEffect(() => {
    if (pathRef.current) {
      setPathLength(pathRef.current.getTotalLength());
    }
  }, [track]);

  useEffect(() => {
    if (pathLength === 0 || !pathRef.current) return;

    let frameId: number;
    let lastTime = performance.now();
    const averageLapTime = 90;

    const updatePoints = (time: number) => {
      const delta = (time - lastTime) / 1000;
      lastTime = time;

      setVirtualLapProgress((prev) => (prev + delta / averageLapTime) % 1);

      if (drivers && drivers.length > 0) {
        const nextPoints: typeof driverPoints = {};

        drivers.forEach((d) => {
          if (!pathRef.current) return;

          let progress = 0;

          if (d.status === 'RETIRED' || d.status === 'OUT') {
            const seed = d.code.charCodeAt(0) + d.code.charCodeAt(1);
            progress = (seed % 100) / 100;
          } else if (d.status === 'IN PIT') {
            progress = 0.99;
          } else {
            const gapSecs = d.gapToLeader || 0;
            const progressOffset = gapSecs / averageLapTime;
            progress = (virtualLapProgress - progressOffset + 1) % 1;
          }

          try {
            const pt = pathRef.current.getPointAtLength(progress * pathLength);
            
            let px = pt.x;
            let py = pt.y;
            if (d.status === 'IN PIT') {
              px += 8 + (d.position * 1.5);
              py += 8;
            }

            nextPoints[d.driverId] = {
              x: px,
              y: py,
              code: d.code,
              color: getTeamColor(d.teamId || ''),
              position: d.position,
              status: d.status
            };
          } catch {
            // Safeguard SVG errors
          }
        });

        setDriverPoints(nextPoints);
      }

      frameId = requestAnimationFrame(updatePoints);
    };

    frameId = requestAnimationFrame(updatePoints);
    return () => cancelAnimationFrame(frameId);
  }, [pathLength, drivers, virtualLapProgress]);

  const activeCorners = track.corners || [];

  return (
    <div className="flex flex-col gap-4 w-full">
      <div 
        style={{
          background: '#07090E',
          border: '1px solid var(--line)',
          borderRadius: '8px',
          padding: '16px',
          position: 'relative',
          overflow: 'hidden',
          boxShadow: '0 8px 32px rgba(0, 0, 0, 0.5)',
          backgroundImage: 'radial-gradient(rgba(42, 47, 58, 0.15) 1px, transparent 1px)',
          backgroundSize: '16px 16px'
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px', borderBottom: '1px solid rgba(42, 47, 58, 0.4)', paddingBottom: '8px' }}>
          <span style={{ fontSize: '24px' }}>{track.flag}</span>
          <div>
            <h3 style={{ margin: 0, fontFamily: 'var(--font-display)', fontSize: '20px', letterSpacing: '0.5px', color: 'var(--paper)' }}>
              {track.name.toUpperCase()}
            </h3>
            <span style={{ fontSize: '11px', fontFamily: 'var(--font-mono)', color: 'var(--dim)' }}>
              {track.country.toUpperCase()} &bull; TRACK RADAR CONSOLE
            </span>
          </div>
        </div>

        <svg 
          viewBox={track.viewBox || "0 0 600 400"} 
          width="100%" 
          height="100%" 
          style={{ display: 'block', maxHeight: '350px' }}
        >
          <defs>
            <pattern id="grid" width="30" height="30" patternUnits="userSpaceOnUse">
              <path d="M 30 0 L 0 0 0 30" fill="none" stroke="rgba(255, 255, 255, 0.03)" strokeWidth="1" />
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#grid)" />

          <path 
            ref={pathRef} 
            d={track.fullPath} 
            fill="none" 
            stroke="transparent" 
            strokeWidth="0" 
          />

          {/* Asphalt Backing Roads for enhanced visual clarity */}
          <path 
            d={track.fullPath} 
            fill="none" 
            stroke="#12151B" 
            strokeWidth="9" 
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ opacity: 0.95 }}
          />
          <path 
            d={track.fullPath} 
            fill="none" 
            stroke="#1B1F27" 
            strokeWidth="7" 
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ opacity: 0.8 }}
          />

          {/* Sector 1 (Red) - Glow & Main Stroke */}
          <path 
            d={track.s1} 
            fill="none" 
            stroke="var(--red)" 
            strokeWidth="5" 
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ opacity: 0.25, filter: 'blur(3px)' }}
          />
          <path 
            d={track.s1} 
            fill="none" 
            stroke="var(--red)" 
            strokeWidth="3.2" 
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ opacity: 0.95 }}
          />

          {/* Sector 2 (Cyan) - Glow & Main Stroke */}
          <path 
            d={track.s2} 
            fill="none" 
            stroke="var(--cyan)" 
            strokeWidth="5" 
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ opacity: 0.25, filter: 'blur(3px)' }}
          />
          <path 
            d={track.s2} 
            fill="none" 
            stroke="var(--cyan)" 
            strokeWidth="3.2" 
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ opacity: 0.95 }}
          />

          {/* Sector 3 (Purple) - Glow & Main Stroke */}
          <path 
            d={track.s3} 
            fill="none" 
            stroke="var(--purple)" 
            strokeWidth="5" 
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ opacity: 0.25, filter: 'blur(3px)' }}
          />
          <path 
            d={track.s3} 
            fill="none" 
            stroke="var(--purple)" 
            strokeWidth="3.2" 
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ opacity: 0.95 }}
          />

          {/* Corner Numbers */}
          {activeCorners.map((corner, i) => (
            <g key={i} transform={`translate(${corner.x}, ${corner.y})`}>
              <rect 
                x="-10" 
                y="-10" 
                width="20" 
                height="20" 
                rx="3" 
                fill="#0F121C" 
                stroke="var(--line)" 
                strokeWidth="1" 
              />
              <text 
                textAnchor="middle" 
                dominantBaseline="middle" 
                fill="var(--dim)" 
                fontSize="9" 
                fontWeight="bold" 
                fontFamily="var(--font-mono)"
              >
                {corner.n}
              </text>
            </g>
          ))}

          {track.speedTrap && (
            <g transform={`translate(${track.speedTrap.x}, ${track.speedTrap.y})`}>
              <line x1="0" y1="0" x2="35" y2="-25" stroke="#E8302A" strokeWidth="1.5" strokeDasharray="3 2" />
              <circle cx="0" cy="0" r="4" fill="#E8302A" />
              <g transform="translate(35, -38)">
                <rect x="-10" y="0" width="70" height="22" rx="4" fill="#FF007F" />
                <text x="25" y="14" textAnchor="middle" fill="#FFFFFF" fontSize="9" fontWeight="bold" fontFamily="var(--font-display)">
                  SPEED TRAP
                </text>
              </g>
            </g>
          )}

          {track.startFinish && (
            <g transform={`translate(${track.startFinish.x}, ${track.startFinish.y}) rotate(${track.startFinish.angle})`}>
              <line x1="-15" y1="0" x2="15" y2="0" stroke="var(--paper)" strokeWidth="2.5" strokeDasharray="4 2" />
              <text x="0" y="-8" textAnchor="middle" fontSize="13">🏁</text>
            </g>
          )}

          {Object.entries(driverPoints).map(([driverId, pt]) => {
            const isHovered = activeDriverCode === pt.code;
            const isRetired = pt.status === 'RETIRED' || pt.status === 'OUT';
            const inPit = pt.status === 'IN PIT';

            return (
              <g 
                key={driverId}
                onMouseEnter={() => onHoverDriver?.(pt.code)}
                onMouseLeave={() => onHoverDriver?.(null)}
                style={{ cursor: 'pointer', transition: 'all 0.1s ease-out' }}
              >
                <circle 
                  cx={pt.x} 
                  cy={pt.y} 
                  r={isHovered ? 14 : 9} 
                  fill="none" 
                  stroke={isRetired ? '#8E8E93' : pt.color} 
                  strokeWidth="2.5" 
                  opacity={isHovered ? 0.9 : 0.4} 
                  style={{ transition: 'r 0.15s ease' }}
                />

                <circle 
                  cx={pt.x} 
                  cy={pt.y} 
                  r={isHovered ? 8 : 6} 
                  fill={isRetired ? '#1F242E' : inPit ? '#FF9F0A' : '#0B0D13'} 
                  stroke={isRetired ? '#8E8E93' : inPit ? '#FF9F0A' : pt.color} 
                  strokeWidth="2.5" 
                  style={{ transition: 'r 0.15s ease' }}
                />

                <g transform={`translate(${pt.x + 10}, ${pt.y - 8})`}>
                  <rect 
                    x="-2" 
                    y="-8" 
                    width="26" 
                    height="12" 
                    rx="2" 
                    fill="#05070A" 
                    stroke={isHovered ? pt.color : 'rgba(42, 47, 58, 0.6)'} 
                    strokeWidth="0.8" 
                    opacity="0.85"
                  />
                  <text 
                    x="11" 
                    y="1.5" 
                    textAnchor="middle" 
                    fill={isRetired ? '#8E8E93' : '#EEF1F6'} 
                    fontSize="7.5" 
                    fontWeight="bold" 
                    fontFamily="var(--font-mono)"
                  >
                    {pt.code}
                  </text>
                </g>
              </g>
            );
          })}
        </svg>

        <div 
          style={{
            position: 'absolute',
            bottom: '12px',
            left: '12px',
            background: 'rgba(7, 9, 14, 0.85)',
            border: '1px solid var(--line)',
            borderRadius: '4px',
            padding: '6px 10px',
            display: 'flex',
            gap: '12px',
            fontSize: '10px',
            fontFamily: 'var(--font-mono)'
          }}
        >
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
            <span style={{ width: '8px', height: '8px', background: 'var(--red)', borderRadius: '50%' }}></span>
            <span>Sector 1</span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
            <span style={{ width: '8px', height: '8px', background: 'var(--cyan)', borderRadius: '50%' }}></span>
            <span>Sector 2</span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
            <span style={{ width: '8px', height: '8px', background: 'var(--purple)', borderRadius: '50%' }}></span>
            <span>Sector 3</span>
          </div>
          {drivers.length > 0 && (
            <>
              <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                <span style={{ width: '8px', height: '8px', background: '#FF9F0A', borderRadius: '50%' }}></span>
                <span style={{ color: '#FF9F0A' }}>In Pit</span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                <span style={{ width: '8px', height: '8px', background: '#8E8E93', borderRadius: '50%' }}></span>
                <span style={{ color: '#8E8E93' }}>Retired</span>
              </div>
            </>
          )}
        </div>
      </div>

      {showStats && (
        <div 
          className="stat-grid" 
          style={{ 
            gridTemplateColumns: 'repeat(auto-fit, minmax(130px, 1fr))',
            gap: '12px'
          }}
        >
          <div className="stat-box" style={{ borderLeft: '3px solid var(--red)' }}>
            <div className="k">Circuit Length</div>
            <div className="v" style={{ fontSize: '19px', fontFamily: 'var(--font-display)', color: 'var(--paper)' }}>
              {track.length}
            </div>
          </div>
          <div className="stat-box" style={{ borderLeft: '3px solid var(--cyan)' }}>
            <div className="k">Race Distance</div>
            <div className="v" style={{ fontSize: '19px', fontFamily: 'var(--font-display)', color: 'var(--paper)' }}>
              {track.distance}
            </div>
          </div>
          <div className="stat-box" style={{ borderLeft: '3px solid var(--amber)' }}>
            <div className="k">Number of Laps</div>
            <div className="v" style={{ fontSize: '19px', fontFamily: 'var(--font-display)', color: 'var(--paper)' }}>
              {track.laps}
            </div>
          </div>
          <div className="stat-box" style={{ borderLeft: '3px solid var(--purple)' }}>
            <div className="k">Lap Record</div>
            <div className="v" style={{ fontSize: '15px', color: 'var(--paper)' }}>
              {track.record.split(' ')[0]}
            </div>
            <div className="footnote" style={{ fontSize: '9px', marginTop: '2px' }}>
              {track.record.split(' ').slice(1).join(' ')}
            </div>
          </div>
          <div className="stat-box" style={{ borderLeft: '3px solid var(--green)' }}>
            <div className="k">Defending Champion</div>
            <div className="v" style={{ fontSize: '17px', fontFamily: 'var(--font-display)', color: 'var(--paper)' }}>
              {track.champion}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
